// Strict UTC only. Only checkOutZonedDateTime from Hostfully. scheduledCleaningTimeUTC = checkoutTimeUTC.
const ZONED_REGEX = /[zZ]|[+-]\d{2}:\d{2}$/;
const j = $input.first().json;
// Always read the zoned checkout from Merge Lead and Lookup so we keep the Hostfully field
// even when this node is reached via Create Reservation Record.
const lead = (() => {
  try {
    const n = $('Merge Lead and Lookup');
    if (n && typeof n.last === 'function') {
      const v = n.last().json;
      if (v && typeof v === 'object') return v;
    }
  } catch (_) {}
  return j || {};
})();
const bookingUid = lead?.uid || lead?.bookingUid || j?.uid || j?.bookingUid || '';
const cleaningJobId = bookingUid ? bookingUid + '_CLEAN' : '';
const rawCheckout = lead?.checkOutZonedDateTime;
if (!rawCheckout || typeof rawCheckout !== 'string' || rawCheckout.trim() === '')
  throw new Error('Missing required column configuration: checkout time not provided');
const s = rawCheckout.trim();
if (!ZONED_REGEX.test(s))
  throw new Error('Invalid checkout time: timezone offset or Z required');
const checkoutDate = new Date(s);
if (isNaN(checkoutDate.getTime()))
  throw new Error('Invalid checkout time: cannot parse date');
const checkoutTimeUTC = checkoutDate.toISOString();
const scheduledCleaningTimeUTC = checkoutTimeUTC;
const dateTime = s;
return [{ json: { cleaningJobId, bookingUid, propertyUid: lead?.propertyUid ?? j?.propertyUid ?? '', cleaningDate: dateTime, cleaningTime: dateTime, checkoutTimeUTC, scheduledCleaningTimeUTC, status: 'PENDING', assignedCleaner: '', clockIn: '', clockOut: '', workedHours: '', createdAtSystem: new Date().toISOString() } }];

// Run after Ensure One Item; read lead from Split In Batches and lookup from Ensure One Item.
const lead = $('Split In Batches').last().json;
const lookup = $('Ensure One Item').last().json;
return [{ json: { ...lead, ...lookup } }];

let items = [];
try { if ($input && typeof $input.all === 'function') items = $input.all(); } catch (_) {}
if (!items.length) return [{ json: { _noMatch: true } }];
const first = items[0].json || {};
// When Lookup has "Always output data", 0 rows still send one item - treat as no match if no real reservation data
const hasRealMatch = first.bookingUid !== undefined && first.bookingUid !== null && String(first.bookingUid).trim() !== '';
if (!hasRealMatch) return [{ json: { _noMatch: true } }];
return [{ json: { ...first, _noMatch: false } }];

const data = $('Accumulate Leads').last().json;
const leads = data?.accumulatedLeads || [];
let maxUpdated = null;
for (const lead of leads) {
  const t = lead?.metadata?.updatedUtcDateTime;
  if (t && (!maxUpdated || t > maxUpdated)) maxUpdated = t;
}
let newStoredTimestamp = maxUpdated || data?.storedTimestamp || '1970-01-01T00:00:00.000Z';
// Advance by 1 ms so the next run never sees "equal" timestamp (avoids skipping a booking forever)
if (maxUpdated) {
  const d = new Date(newStoredTimestamp);
  d.setUTCMilliseconds(d.getUTCMilliseconds() + 1);
  newStoredTimestamp = d.toISOString();
}
return [{ json: { key: 'config', storedTimestamp: newStoredTimestamp } }];

const storedTimestamp = $('Accumulate Leads').last().json?.storedTimestamp || '1970-01-01T00:00:00.000Z';
const items = $input.all();
const filtered = [];
for (const item of items) {
  const lead = item.json;
  const created = lead?.metadata?.createdUtcDateTime;
  if (created && created > storedTimestamp && lead?.type === 'BOOKING' && lead?.status === 'BOOKED') {
    filtered.push(item);
  }
}
return filtered;

const data = $('Accumulate Leads').last().json;
const leads = data?.accumulatedLeads || [];
const storedTimestamp = data?.storedTimestamp
  || '1970-01-01T00:00:00.000Z';

const ZONED_REGEX = /[zZ]|[+-]\d{2}:\d{2}$/;

const candidates = [];

for (const lead of leads) {
  const created = lead?.metadata?.createdUtcDateTime;
  const updated = lead?.metadata?.updatedUtcDateTime;

  if (lead?.type !== 'BOOKING' || lead?.status !== 'BOOKED') continue;
  if (!updated || !created) continue;
  if (updated <= storedTimestamp) continue;
  if (created > storedTimestamp) continue;

  const rawZoned = lead?.checkOutZonedDateTime;
  if (!rawZoned || !ZONED_REGEX.test(rawZoned.trim())) continue;

  const checkoutDate = new Date(rawZoned.trim());
  if (isNaN(checkoutDate.getTime())) continue;

  const checkoutTimeUTC = checkoutDate.toISOString();

  // Use local datetime for display fields (not UTC)
  const localDT = lead.checkOutLocalDateTime || '';
  const newCleaningDate = localDT.substring(0, 10);   // e.g. 2026-04-24
  const newCleaningTime = localDT.substring(11, 16);  // e.g. 10:00

  candidates.push({
    bookingUid: lead.uid || '',
    propertyUid: lead.propertyUid || '',
    newCheckOut: lead.checkOutLocalDateTime || '',
    newCheckoutTimeUTC: checkoutTimeUTC,
    newScheduledCleaningTimeUTC: checkoutTimeUTC,
    newCleaningDate,
    newCleaningTime,
    _hostfullyCheckoutUTC: checkoutTimeUTC
  });
}

return candidates.map(c => ({ json: c }));

// Build a map of bookingUid -> sheet checkout time (local)
const lookupItems = $input.all();
const sheetCheckouts = {};
for (const item of lookupItems) {
  const uid = (item.json.bookingUid ?? '').toString().trim();
  const co = (item.json.checkOut ?? '').toString().trim();
  if (uid) sheetCheckouts[uid] = co;
}

// Normalize a local datetime string to "YYYY-MM-DDTHH:MM:SS" for safe
// string comparison. Handles both "2026-03-25 10:00:00" and
// "2026-03-25T10:00:00" formats. Both sides are local time so no UTC
// conversion needed — avoids the space-vs-T timezone parsing pitfall.
const normalizeLocal = (s) => s.replace(' ', 'T').substring(0, 19);

// Only pass through candidates where:
// 1. Reservation exists in sheet
// 2. Hostfully local checkout is strictly LATER than the stored local checkout
const candidates = $('Split Extended Candidates').all();
const results = [];

for (const item of candidates) {
  const uid = (item.json.bookingUid ?? '').toString().trim();
  if (!uid) continue;
  const sheetCO = sheetCheckouts[uid];
  if (!sheetCO) continue; // not in sheet at all

  const sheetLocal = normalizeLocal(sheetCO);               // e.g. "2026-03-25T10:00:00"
  const newLocal = normalizeLocal(item.json.newCheckOut ?? ''); // e.g. "2026-03-25T10:00:00"

  if (!newLocal || newLocal <= sheetLocal) continue; // same or earlier = not extended

  // Strip the internal helper field before passing downstream
  const { _hostfullyCheckoutUTC, ...clean } = item.json;
  results.push({ json: clean });
}

return results;

// Use previous run of Accumulate Leads when runIndex > 0, else Initialize Cursor
const isFirstRun = typeof $runIndex === 'undefined' || $runIndex === 0;
const previousData = isFirstRun
  ? $('Initialize Cursor').first().json
  : $('Accumulate Leads').first(0, $runIndex - 1).json;

const response = $('Fetch Hostfully Leads').all()[0].json;
const newLeads = response.leads || [];
const nextCursor = response._paging?._nextCursor ?? null;
const storedTimestamp = previousData.storedTimestamp;

return [{
  json: {
    cursor: nextCursor,
    accumulatedLeads: [...(previousData.accumulatedLeads || []), ...newLeads],
    storedTimestamp: storedTimestamp
  }
}];

let storedTimestamp = '1970-01-01T00:00:00.000Z';
try {
  const readOut = $('Read Last Timestamp').first().json;
  const raw = readOut?.storedTimestamp || readOut?.lastProcessedTimestamp;
  if (typeof raw === 'string') {
    storedTimestamp = raw.includes(' ') ? raw.replace(' ', 'T') : raw;
  } else if (raw) {
    storedTimestamp = raw;
  }
} catch (_) {}
return [{ json: { cursor: null, accumulatedLeads: [], storedTimestamp } }];

const leads = $('Accumulate Leads').last().json?.accumulatedLeads ?? [];
const candidates = leads.filter(l =>
  l.type === 'BOOKING' &&
  l.status === 'CANCELLED'
);
return candidates.map(c => ({ json: c }));

// Build a map of sheet reservations keyed by bookingUid
const lookupItems = $input.all();
const sheetMap = {};
for (const item of lookupItems) {
  const uid = (item.json.bookingUid ?? '').toString().trim();
  if (uid) sheetMap[uid] = item.json;
}

// For each cancelled candidate, check if it exists in the sheet
const candidates = $('Detect Cancellations').all();
const results = [];

for (const item of candidates) {
  const candidate = item.json;
  const uid = (candidate.uid ?? '').toString().trim();
  if (!uid) continue;

  const sheetRow = sheetMap[uid];

  // Skip if no reservation row found in sheet
  if (!sheetRow) continue;

  // Skip if already cancelled in sheet (idempotency)
  const status = (sheetRow.cleaningStatus ?? '').toString().trim().toUpperCase();
  if (status === 'CANCELLED') continue;

  results.push({ json: candidate });
}

return results;
